<span class="line"><span style="color:#F38BA8;">        self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">tool_to_server</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">clear</span><span style="color:#9399B2;">();</span></span>
